FNePyObject_Actor* NePyObjectNew_Actor(AActor* InValue, PyTypeObject* InPyType)
{
	check(PyType_IsSubtype(InPyType, &FNePyObjectType_Actor));
	FNePyObject_Actor* RetValue = (FNePyObject_Actor*)InPyType->tp_alloc(InPyType, 0);
	RetValue->Value = InValue;
	return RetValue;
}

FNePyObject_Actor* NePyObjectCheck_Actor(PyObject* InPyObj)
{
	if (InPyObj && PyObject_IsInstance(InPyObj, (PyObject*)&FNePyObjectType_Actor))
	{
		return (FNePyObject_Actor*)InPyObj;
	}
	return nullptr;
}

PyTypeObject* NePyObjectGetType_Actor()
{
	return &FNePyObjectType_Actor;
}

PyTypeObject* NePyNePyWrappedClassInit_Actor(const UClass* InClass, PyTypeObject* InPyBase, PyObject* InPyBases)
{
	PyTypeObject* NePyObjectType = &FNePyObjectType_Actor;
	NePyObjectType_InitCommon(NePyObjectType);
	NePyObjectType->tp_getset = FNePyObjectType_Actor_getset;
	NePyObjectType->tp_methods = FNePyObjectType_Actor_methods;
	NePyObjectType->tp_base = InPyBase;
	NePyObjectType->tp_bases = InPyBases;
	PyType_Ready(NePyObjectType);

	FNePyObjectTypeInfo TypeInfo = {
		NePyObjectType,
		ENePyTypeFlags::StaticPyType,
		(NePyObjectNewFunc)NePyObjectNew_Actor,
	};
	FNePyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, TypeInfo);

	return NePyObjectType;
}

void NePyInitObject_Actor(PyObject* PyOuterModule)
{
	FNePyWrapperInitializer::Get().RegisterWrappedClassInitFunc(
		AActor::StaticClass(), NePyNePyWrappedClassInit_Actor);
}

namespace NePyBase
{
	bool ToCpp(PyObject* InPyObj, AActor*& OutVal)
	{
		if (FNePyObject_Actor* PyObj = NePyObjectCheck_Actor(InPyObj))
		{
			if (FNePyHouseKeeper::Get().IsValid(PyObj))
			{
				OutVal = PyObj->GetValue();
				return true;
			}
		}
		return false;
	}
}

